import type { ScenarioQuestion } from "./types";
type D = "beginner" | "intermediate" | "advanced";
function q(id: string, g: string, s: string, sc: string, qu: string, a: string, f: string, d: D): ScenarioQuestion {
  return { id, formatType: "scenario", categoryGroup: g, subcategory: s, scenarioPrompt: sc, question: qu, exampleAnswer: a, feedback: f, difficulty: d };
}
const ip = "interview_preparation", ws = "workplace_scenarios", ct = "clinical_transition", pd = "professional_development", cn = "career_navigation";

export const bulkGeneratedBatch4: ScenarioQuestion[] = [
  q("sq-bg4-1",ip,"behavioral","You demonstrated leadership during a group project.","How did you show leadership in an academic setting?","I led a community health assessment project where team members had conflicting schedules and ideas. I created a shared digital workspace, established clear roles based on each member's strengths, set weekly milestones, and facilitated consensus when disagreements arose. We delivered an A-grade project and received recognition from the department.","Practical leadership through organization and facilitation.","beginner"),
  q("sq-bg4-2",ip,"behavioral","You had to adapt quickly to a change in clinical placement.","How do you handle unexpected changes?","My med-surg clinical placement was changed to a pediatric unit two days before it started. Instead of panicking, I immediately reviewed pediatric assessment techniques, medication dosing differences, and developmental milestones. I arrived prepared and discovered that the unexpected change actually broadened my skills significantly.","Rapid adaptation with proactive preparation.","beginner"),
  q("sq-bg4-3",ip,"behavioral","You are asked about what makes you unique as a candidate.","What unique qualities do you bring to nursing?","I bring a dual perspective from my background as an EMT before nursing school. I understand the pre-hospital mindset, can anticipate what information paramedics need during patient handoff, and have composure during emergencies that comes from years of field experience. This background makes me especially effective in emergency and trauma settings.","Leveraging unique background for clinical advantage.","beginner"),
  q("sq-bg4-4",ip,"clinical_judgment","A patient develops abdominal distension and absent bowel sounds post-operatively.","What post-operative complication do you suspect?","Abdominal distension with absent bowel sounds suggests paralytic ileus—a temporary cessation of bowel motility common after abdominal surgery. I would keep the patient NPO, insert or maintain NG tube suction if ordered, ensure ambulation when safe, monitor for return of bowel sounds, and check electrolytes as hypokalemia can worsen ileus.","Post-operative ileus recognition and management.","intermediate"),
  q("sq-bg4-5",ip,"clinical_judgment","A patient on phenytoin has a serum level of 30 mcg/mL.","What does a toxic phenytoin level indicate?","Phenytoin therapeutic range is 10-20 mcg/mL. A level of 30 is toxic and can cause nystagmus, ataxia, slurred speech, confusion, and potentially fatal cardiac arrhythmias. I would hold the medication, assess for toxicity symptoms, notify the provider, obtain cardiac monitoring, and anticipate dose adjustment. I would check albumin level as hypoalbuminemia increases free phenytoin.","Phenytoin toxicity recognition with albumin consideration.","advanced"),
  q("sq-bg4-6",ip,"clinical_judgment","A patient with a history of mitral valve prolapse develops sudden fever and petechiae.","What serious condition might this indicate?","Fever with petechiae in a patient with mitral valve prolapse raises concern for infective endocarditis—bacterial infection of the heart valve. I would draw multiple blood cultures from different sites, assess for other signs (Osler nodes, Janeway lesions, splinter hemorrhages), and notify the provider immediately. Echocardiography and prolonged IV antibiotic therapy will likely be needed.","Endocarditis recognition in predisposed patients.","advanced"),
  q("sq-bg4-7",ip,"clinical_judgment","A patient with cirrhosis develops confusion and asterixis.","What does this presentation indicate?","Confusion with asterixis (liver flap) in a cirrhosis patient indicates hepatic encephalopathy—the liver cannot clear ammonia and other toxins from the blood. I would check ammonia level, initiate lactulose therapy to promote ammonia excretion, restrict protein per orders, assess the encephalopathy grade, and identify triggers such as GI bleeding, infection, or electrolyte imbalances.","Hepatic encephalopathy with trigger identification.","intermediate"),
  q("sq-bg4-8",ip,"clinical_judgment","A patient receiving amphotericin B develops fever and rigors during the infusion.","Is this an expected or concerning reaction?","Fever and rigors during amphotericin B infusion are common and expected—known as 'shake and bake' reactions. I would slow the infusion rate, administer premedications (diphenhydramine, acetaminophen, meperidine for rigors) as ordered, monitor vital signs closely, and continue the infusion if the patient tolerates it. However, I would watch for more serious signs like hypotension or bronchospasm.","Differentiating expected from dangerous infusion reactions.","intermediate"),
  q("sq-bg4-9",ip,"clinical_judgment","A patient post-thyroidectomy develops tingling around the mouth and fingertips.","What electrolyte abnormality do you suspect?","Perioral and fingertip tingling after thyroidectomy suggests hypocalcemia from accidental parathyroid gland damage or removal. I would check for Chvostek sign (facial twitching with cheek tap) and Trousseau sign (carpal spasm with BP cuff inflation), draw a stat calcium level, notify the surgeon, and have IV calcium gluconate available. Severe hypocalcemia can cause laryngospasm and cardiac arrest.","Post-thyroidectomy hypocalcemia emergency recognition.","advanced"),
  q("sq-bg4-10",ip,"clinical_judgment","A patient with a colostomy has no output for 3 days.","What might cause absent colostomy output?","Absent colostomy output for 3 days suggests obstruction from food blockage, adhesions, or stoma edema. I would assess the stoma for color (should be pink and moist), edema, and patency. I would assess for abdominal distension, pain, nausea, and vomiting. I would keep the patient NPO, notify the provider, and anticipate imaging. I would not irrigate without a physician order.","Colostomy obstruction assessment.","intermediate"),
  q("sq-bg4-11",ip,"scenario_responses","A patient asks if their condition is serious enough to require hospitalization.","How would you respond to a patient questioning the need for hospitalization?","I would explain their condition and the medical reasoning: 'Your physician admitted you because [specific clinical reason] needs monitoring and treatment that cannot be safely done at home right now. We want to make sure you are stable before discharge.' I would encourage them to discuss specific concerns with their physician.","Clear clinical explanation without making discharge decisions.","beginner"),
  q("sq-bg4-12",ip,"scenario_responses","A patient in isolation asks you to bring their pet to visit.","How would you handle a pet visitation request in isolation?","I would explain that while I understand how comforting their pet would be, isolation precautions prevent non-essential visitors, including pets, to protect both the patient and others. I would suggest video calls with family showing the pet, photos at the bedside, or exploring the facility's pet therapy policy for after isolation ends.","Compassionate denial with creative alternatives.","beginner"),
  q("sq-bg4-13",ws,"prioritization","A rapid response is called on another unit while you are in the middle of a blood transfusion.","How would you manage competing urgent situations?","I would not leave my transfusion patient unmonitored. Rapid responses have dedicated response teams. I would continue monitoring my patient and complete the transfusion safety checks. If specifically called to assist, I would ask a colleague to monitor my transfusion patient with clear instructions about what to watch for before leaving.","Maintaining current patient safety during system emergencies.","intermediate"),
  q("sq-bg4-14",ws,"prioritization","You have a new admission coming, a discharge to process, and a patient requesting pain medication.","How would you sequence these three tasks?","Pain medication first—it is a patient in current need and takes 5-10 minutes. Then prepare the discharge because the patient is waiting to leave. The new admission can be directed to the room by support staff while I complete the discharge. I would communicate timelines to all three patients.","Patient need-based sequencing with communication.","beginner"),
  q("sq-bg4-15",ws,"delegation","A float nurse is assigned to help on your unit but does not know the layout.","How would you orient a float nurse quickly?","I would provide a rapid orientation: medication room location, supply room, emergency equipment, code blue button, and key phone numbers. I would assign them patients with straightforward needs and pair them with an experienced nurse for questions. I would check in frequently and ensure they have the resources to provide safe care.","Rapid float nurse orientation for safe coverage.","beginner"),
  q("sq-bg4-16",ws,"patient_safety","A patient's bed is found in the highest position with side rails down.","How would you address an unsafe bed position?","I would immediately lower the bed and raise appropriate side rails. I would assess who last adjusted the bed and why it was left in an unsafe position. I would reeducate the patient about using the call bell and keeping the bed in the lowest locked position. I would document the finding and any interventions.","Immediate correction of fall risk factors.","beginner"),
  q("sq-bg4-17",ws,"patient_safety","A patient on a PCA pump has a respiratory rate of 8.","What does this respiratory rate indicate?","A respiratory rate of 8 in a PCA patient suggests opioid-induced respiratory depression. I would stop the PCA pump, stimulate the patient vigorously, assess oxygen saturation, apply oxygen, prepare naloxone, and call for help. I would notify the provider and anticipate PCA settings adjustment or alternative pain management. I would not restart the PCA without provider evaluation.","Opioid respiratory depression as a PCA emergency.","intermediate"),
  q("sq-bg4-18",ws,"medication_error","A nurse reports that a controlled substance count is off by one.","How would you handle a controlled substance discrepancy?","I would stop and immediately recount with a witness. I would review the dispensing log for all transactions during the shift. I would check wasted medication documentation. I would notify the charge nurse and pharmacy if the discrepancy cannot be resolved. Controlled substance discrepancies require immediate investigation and incident reporting. This is both a safety and a legal issue.","Systematic controlled substance discrepancy investigation.","intermediate"),
  q("sq-bg4-19",ws,"medication_error","You realize a medication you hung has been infusing at the wrong rate for 2 hours.","How would you handle a 2-hour infusion rate error?","I would correct the rate immediately, assess the patient for adverse effects, calculate the total volume received versus what should have been given, and notify the provider with the specific deviation. I would document the error, adjusted rate, and patient assessment. I would file an incident report. I would determine how the error occurred—pump programming, calculation, or miscommunication.","Infusion rate error recovery with dose impact calculation.","intermediate"),
  q("sq-bg4-20",ws,"handoff_communication","You disagree with the outgoing nurse's clinical assessment.","How would you handle disagreement during received handoff?","I would ask clarifying questions: 'Can you tell me more about why you assessed the patient that way?' I would reserve judgment until I perform my own assessment. If I find something significantly different, I would document my findings and follow up with the provider if needed. Handoff is not the time for arguments—it is the time for information exchange.","Professional disagreement handling during handoff.","beginner"),
  q("sq-bg4-21",ws,"difficult_coworkers","A colleague takes credit for your work during a staff meeting.","How would you address credit-taking by a colleague?","I would address it privately after the meeting: 'I noticed you presented the fall prevention data that I collected and analyzed. I would appreciate being credited for my contributions in the future.' If it happened again, I would speak up during the meeting: 'Thank you for presenting this. I want to add some context since I collected this data.' I would also ensure my contributions are documented.","Direct credit reclamation with prevention strategies.","intermediate"),
  q("sq-bg4-22",ws,"interdisciplinary_communication","A respiratory therapist questions why a patient is not on the ventilator settings they recommended.","How would you facilitate RT-physician communication?","I would listen to the RT's clinical reasoning and say, 'I understand your recommendation. Let me help connect you with the physician to discuss the ventilator settings directly. Your clinical expertise is important for this patient's respiratory management.' I would not act as a mediator for ventilator management decisions—I would facilitate direct communication.","Facilitating direct specialist-to-physician communication.","intermediate"),
  q("sq-bg4-23",ct,"first_shift","You accidentally contaminate a sterile field and no one else saw it.","How would you handle a sterile field contamination with no witnesses?","I would stop, obtain new sterile supplies, and start the sterile setup again. I would not proceed with a contaminated field even though no one witnessed it. Patient safety is not dependent on being watched. I would consider it a learning opportunity and analyze what led to the contamination to prevent it in the future.","Self-accountability without external oversight.","beginner"),
  q("sq-bg4-24",ct,"new_nurse_anxiety","You dread going to work because of anxiety about patient care.","How would you address work-related anxiety that affects your daily life?","I would recognize that persistent dread is different from normal new nurse nervousness. I would talk to my preceptor or manager about my specific fears. I would utilize the Employee Assistance Program for professional support. I would identify whether the anxiety is related to specific skills that can be improved through education and practice or if it is generalized anxiety that needs professional treatment.","Distinguishing normal nervousness from clinical anxiety.","intermediate"),
  q("sq-bg4-25",ct,"time_management","You spend too much time preparing medications and fall behind schedule.","How would you improve medication preparation efficiency?","I would organize my medication preparation by patient and by time, batch medications when possible, prepare for anticipated PRN requests, and pre-review each patient's medication list before the medication pass. I would learn the dispensing system's shortcuts and anticipate access issues by verifying orders early. Efficiency comes from preparation and system familiarity.","Systematic medication preparation improvement.","beginner"),
  q("sq-bg4-26",ct,"documentation_challenges","You are not sure whether to document a patient's exact words or paraphrase.","When should you use direct quotes in nursing documentation?","Direct quotes should be used for significant patient statements: pain descriptions, symptoms in their own words, threats of self-harm, statements about abuse, and refusals of care. Quoting preserves the patient's exact expression and is important for legal documentation. For routine education and conversations, paraphrasing is appropriate.","Strategic use of direct quotes in documentation.","beginner"),
  q("sq-bg4-27",ct,"critical_thinking_drills","A patient's prealbumin level is 8 mg/dL.","What does a low prealbumin level indicate?","Prealbumin (normal 15-36 mg/dL) is a sensitive indicator of current nutritional status. A level of 8 indicates significant protein-calorie malnutrition. I would consult the dietitian for intensive nutritional support, assess for causes of malnutrition (NPO status, malabsorption, increased metabolic demands), and anticipate supplemental nutrition. Prealbumin responds to nutritional changes faster than albumin.","Nutritional status assessment through prealbumin.","intermediate"),
  q("sq-bg4-28",ct,"critical_thinking_drills","A patient has a positive D-dimer but normal ultrasound.","What is the clinical significance of a positive D-dimer with negative ultrasound?","D-dimer is sensitive but not specific—it is elevated in many conditions including infection, inflammation, post-surgery, and pregnancy. A negative ultrasound reduces the probability of DVT, but does not rule out PE. If PE is still clinically suspected, a CT pulmonary angiography should be considered. I would notify the provider about the clinical picture and anticipate further imaging.","Understanding D-dimer limitations and next steps.","intermediate"),
  q("sq-bg4-29",pd,"professional_boundaries","A patient asks for your personal email to send a thank-you note.","How would you redirect a thank-you while maintaining boundaries?","I would say, 'I am so grateful that you want to express your appreciation. While I cannot share personal contact information, you can send a note to the nursing department, write on our unit's gratitude board, or complete a patient satisfaction survey. Your kind words mean a lot.' I would not provide personal contact information.","Gratitude redirection to appropriate channels.","beginner"),
  q("sq-bg4-30",pd,"ethical_dilemmas","A teenage patient asks you not to tell their parents about a positive pregnancy test.","How would you handle a minor's confidentiality request?","I would be aware of my state's laws regarding minor consent for reproductive health. In many states, minors have the right to confidential reproductive healthcare. I would provide compassionate support, ensure the teen has access to prenatal care, discuss options and resources, and encourage them to involve a trusted adult while respecting their legal rights.","State-specific minor confidentiality with supportive care.","advanced"),
  q("sq-bg4-31",pd,"workplace_bullying","You hear staff gossiping about a new nurse's clinical mistakes.","How would you address gossip about a colleague's clinical performance?","I would interrupt the gossip: 'I do not think it is helpful to discuss this behind their back. If there are concerns about clinical performance, the charge nurse or educator should be involved so they can get the support they need.' I would redirect the conversation and model supportive behavior. Gossip about clinical mistakes creates a culture of fear that discourages error reporting.","Gossip interruption with constructive redirection.","beginner"),
  q("sq-bg4-32",pd,"advocacy","A patient with chronic pain is asked to rate their pain on a 1-10 scale but finds it meaningless.","How would you adapt pain assessment for patients who struggle with numeric scales?","I would use alternative pain assessment tools: FACES scale, verbal descriptor scale, or functional assessment (What can you do now vs. when your pain is well-controlled?). I would ask about pain's impact on sleep, appetite, and activity. I would document the alternative method used. Not all patients relate to numeric scales, and accurate pain assessment requires flexible approaches.","Adaptive pain assessment beyond numeric scales.","beginner"),
  q("sq-bg4-33",pd,"patient_communication","A patient repeatedly asks when the doctor is coming.","How would you manage patient expectations about physician visits?","I would be honest about what I know: 'I understand you are waiting. Dr. Smith typically rounds between 9 and 11 AM, but the exact time varies. Is there something I can help you with in the meantime, or a specific question you want answered?' I would document the patient's questions for the physician and communicate their need for a visit.","Managing expectations with transparency and support.","beginner"),
  q("sq-bg4-34",cn,"job_offer_negotiation","You are offered a sign-on bonus with a 2-year repayment clause.","How would you evaluate a sign-on bonus?","I would read the repayment terms carefully: Is the bonus prorated if I leave early? Is it deducted from my final paycheck? Does it apply if I am terminated without cause? I would calculate whether the bonus genuinely benefits me or just locks me into a position. A $5,000 bonus with a $5,000 repayment clause for leaving within 2 years is essentially a retention agreement, not a bonus.","Critical sign-on bonus evaluation.","intermediate"),
  q("sq-bg4-35",cn,"probation_period","Your probation feedback says you need to improve your critical thinking.","How would you develop critical thinking during probation?","I would ask for specific examples of where my critical thinking fell short. I would practice thinking aloud with my preceptor to make my reasoning visible. I would use clinical reasoning frameworks like 'If-then' thinking and SBAR. I would review case studies, participate in simulations, and ask 'why' more frequently. I would seek out complex patients to practice with support available.","Targeted critical thinking development with specific strategies.","intermediate"),
  q("sq-bg4-36",cn,"performance_evaluation","Your evaluation is mostly positive but includes an unexpected negative comment.","How would you process unexpected negative feedback?","I would resist the urge to be defensive. I would ask for specific examples: 'Can you help me understand what situations led to this observation?' I would reflect on whether the feedback has validity even if it is surprising. I would create an action plan to address the concern and follow up in 30 days. Unexpected feedback often reveals blind spots worth exploring.","Non-defensive processing of surprising negative feedback.","intermediate"),
  q("sq-bg4-37",cn,"career_advancement","You are interested in informatics nursing.","How would you pursue a career in nursing informatics?","I would develop technology skills beyond basic EHR use—data analysis, system configuration, and workflow design. I would volunteer for EHR optimization committees. I would pursue informatics certification (RN-BC) and consider a graduate program in nursing informatics. I would network with the IT department and current informaticists. The informatics nurse bridges clinical practice and health information technology.","Nursing informatics career pathway.","intermediate"),
  q("sq-bg4-38",ip,"star_examples","Tell me about a time you demonstrated initiative.","Describe a situation where you went above and beyond.","During clinical, I noticed that the unit's whiteboard communication system was inconsistent—some boards were updated, others were not. Without being asked, I created a standardized whiteboard template with prompts for patient goals, pain management plans, and expected discharge date. After presenting it to the charge nurse, it was adopted unit-wide and patient satisfaction scores for communication improved.","Self-initiated quality improvement.","beginner"),
  q("sq-bg4-39",ip,"clinical_judgment","A patient with COPD suddenly becomes anxious and their oxygen saturation drops to 78%.","What emergency do you suspect?","Sudden anxiety with significant desaturation in a COPD patient could indicate pneumothorax, PE, or COPD exacerbation. I would increase oxygen delivery, assess breath sounds (absent sounds suggest pneumothorax), check vital signs, position the patient upright, and call for help. I would anticipate stat chest X-ray and ABG. If tension pneumothorax is suspected, emergent needle decompression may be needed.","Acute respiratory emergency differential in COPD patients.","advanced"),
  q("sq-bg4-40",ip,"clinical_judgment","A patient develops a facial rash in a butterfly pattern.","What autoimmune condition might this suggest?","A butterfly (malar) rash across the cheeks and nose is a classic sign of systemic lupus erythematosus. I would assess for other lupus symptoms: joint pain, fatigue, photosensitivity, oral ulcers, and fever. I would notify the provider and anticipate orders for ANA, anti-dsDNA, complement levels, and CBC. Early diagnosis and treatment prevent organ damage.","Classic autoimmune presentation recognition.","intermediate"),
  q("sq-bg4-41",ws,"patient_safety","A patient with dementia is found wandering in the hallway at night.","How would you manage a wandering dementia patient?","I would gently redirect the patient to their room without physical restraint. I would assess what triggered the wandering—pain, hunger, toileting needs, or confusion about location. I would implement interventions: bed alarm, door alarms, a wandering management plan, consistent routine, and a safe environment. I would notify the provider and update the care plan. I would not restrain the patient.","Non-restrictive wandering management.","intermediate"),
  q("sq-bg4-42",ws,"medication_error","A patient receives an extra dose of insulin because of a shift change miscommunication.","How would you manage an insulin overdose?","I would assess the patient immediately for hypoglycemia symptoms. I would check blood glucose stat and monitor every 15-30 minutes. I would have dextrose solution available and ensure IV access. I would notify the provider and keep the patient NPO or on clear liquids until glucose stabilizes. I would document the error, complete an incident report, and identify the communication breakdown.","Insulin overdose monitoring and management.","intermediate"),
  q("sq-bg4-43",ct,"first_shift","A patient asks you a question about their prognosis.","How would you handle prognostic questions?","I would acknowledge the importance of the question while recognizing scope boundaries: 'That is a really important question. The best person to discuss your prognosis is your physician, who has the complete picture of your condition. I can help you write down your questions so you can discuss them during the next visit.' I would notify the physician that the patient has prognostic concerns.","Appropriate scope management with patient support.","beginner"),
  q("sq-bg4-44",ct,"critical_thinking_drills","A patient's magnesium level is 1.0 mEq/L.","What does severe hypomagnesemia indicate?","Magnesium of 1.0 (normal 1.5-2.5) is critically low and can cause cardiac arrhythmias, seizures, and neuromuscular irritability. I would place the patient on cardiac monitoring, notify the provider, anticipate IV magnesium replacement, check potassium and calcium as they are often depleted together, and assess for symptoms including Trousseau and Chvostek signs. I would administer replacement slowly due to cardiac risk.","Hypomagnesemia emergency with multi-electrolyte awareness.","advanced"),
  q("sq-bg4-45",pd,"ethical_dilemmas","A patient's adult child asks you to withhold a terminal diagnosis from the patient.","How would you handle a family request to withhold a diagnosis?","I would explain that patients have the right to know their own diagnosis and that withholding information can erode trust and prevent informed decision-making. I would explore the family's concerns—often they are trying to protect their loved one from distress. I would involve the physician in a family meeting to discuss how to communicate the diagnosis compassionately while respecting the patient's autonomy.","Patient autonomy over family protective instincts.","advanced"),
  q("sq-bg4-46",ws,"interdisciplinary_communication","You disagree with a social worker's discharge recommendation.","How would you express disagreement with another discipline's recommendation?","I would express my concern using clinical data: 'I appreciate your assessment. From a nursing perspective, I have concerns about [specific observations] that suggest the patient may not be safe for [recommended plan]. Can we discuss this with the team to find the best solution?' I would focus on patient outcomes rather than professional territory.","Data-based interdisciplinary disagreement.","intermediate"),
  q("sq-bg4-47",cn,"career_advancement","You want to transition from bedside to outpatient nursing.","How would you prepare for an outpatient nursing transition?","I would research outpatient nursing roles: clinic nursing, ambulatory surgery, infusion center, occupational health. I would develop skills in patient education, care coordination, and triage. I would understand the workflow differences—faster pace, higher patient volume, greater autonomy. I would network with outpatient nurses and apply for positions that match my clinical interests.","Outpatient nursing transition preparation.","beginner"),
  q("sq-bg4-48",ip,"behavioral","You are asked about your understanding of patient-centered care.","What does patient-centered care mean to you?","Patient-centered care means treating the whole person, not just the diagnosis. It involves listening to patient preferences, involving them in decisions, respecting their values and beliefs, coordinating care across disciplines, providing emotional support alongside clinical care, and empowering patients with knowledge and resources. It is the difference between caring for a disease and caring for a person.","Comprehensive patient-centered care philosophy.","beginner"),
  q("sq-bg4-49",ws,"difficult_coworkers","A senior nurse dismisses your assessment findings because you are new.","How would you advocate for your clinical assessment despite being dismissed?","I would remain calm and present my findings objectively: 'I understand I am new, but I documented specific changes: heart rate increased from 72 to 110, blood pressure dropped from 130/80 to 95/60, and the patient's mental status changed. These findings concern me for possible hemorrhage. I believe the provider should be notified.' If still dismissed, I would escalate to the charge nurse.","Clinical evidence over seniority hierarchy for patient safety.","intermediate"),
  q("sq-bg4-50",ct,"documentation_challenges","You need to correct an error in the medical record.","How do you properly correct a charting error?","In electronic charting, I would use the system's amendment or addendum function—never delete the original entry. I would note the correction with the date, time, and reason. In paper charting, I would draw a single line through the error, write 'error' above it, initial and date the correction, and write the correct information. Original entries must remain visible and legible.","Proper medical record correction procedures.","beginner"),
  q("sq-bg4-51",ip,"clinical_judgment","A patient receiving vancomycin develops a red, flushed upper body.","What reaction is occurring?","This is Red Man Syndrome—a histamine-mediated reaction to vancomycin caused by rapid infusion. I would slow or stop the infusion, administer diphenhydramine as ordered, and notify the provider. RMS is not a true allergy and does not preclude future vancomycin use. The key is infusing slowly—at least over 60 minutes for a 1-gram dose. I would document the reaction and infusion rate.","Red Man Syndrome differentiation from true allergy.","intermediate"),
  q("sq-bg4-52",ws,"patient_safety","A patient develops hiccups that interfere with eating and sleeping for 48 hours.","How would you manage persistent intractable hiccups?","Persistent hiccups lasting more than 48 hours are considered intractable and warrant medical evaluation. Causes include diaphragmatic irritation, CNS lesions, metabolic derangements, or medications. I would try conservative measures first (swallowing granulated sugar, breath-holding), document the duration and triggers, and notify the provider. Medications like chlorpromazine or baclofen may be needed.","Recognizing intractable hiccups as requiring medical intervention.","intermediate"),
  q("sq-bg4-53",pd,"patient_communication","A patient asks you what you think about alternative medicine.","How would you discuss alternative medicine with a patient?","I would be open and nonjudgmental: 'Many patients find complementary approaches helpful alongside conventional medicine. The most important thing is that we know about everything you are taking or doing so we can ensure it is safe with your treatments. Some natural products can interact with medications. Can you tell me what you have been considering?'","Non-judgmental alternative medicine discussion with safety focus.","beginner"),
  q("sq-bg4-54",cn,"career_advancement","You want to develop trauma nursing expertise.","How would you specialize in trauma nursing?","I would seek employment in a Level 1 or 2 trauma center, obtain TNCC (Trauma Nursing Core Course) certification, pursue CEN (Certified Emergency Nurse) credentials, participate in trauma simulations and drills, and develop skills in rapid assessment, triage, and emergency interventions. I would also consider ATCN (Advanced Trauma Care for Nurses) for advanced-level training.","Structured trauma nursing specialization pathway.","intermediate"),
  q("sq-bg4-55",ip,"clinical_judgment","A patient on digoxin has a heart rate of 52 and reports seeing yellow halos around lights.","What does this presentation suggest?","A heart rate of 52 with visual disturbances (yellow halos) in a patient on digoxin strongly suggests digoxin toxicity. I would hold the medication, check a stat digoxin level and potassium (hypokalemia increases toxicity risk), place the patient on cardiac monitoring, and notify the provider immediately. Severe toxicity may require digoxin immune fab (Digibind).","Digoxin toxicity recognition with classic visual symptoms.","intermediate"),
  q("sq-bg4-56",ws,"delegation","A nursing student asks to perform a task independently.","How would you supervise a nursing student's independent practice?","I would assess whether the student has demonstrated competency in the skill, verify with their clinical instructor that independent practice is appropriate, establish clear parameters and expectations, and ensure I am immediately available if they need help. I would check the patient and documentation after the task is complete. Student supervision is about balancing learning with safety.","Supervised independence with competency verification.","beginner"),
  q("sq-bg4-57",ct,"new_nurse_anxiety","You are the only nurse on the unit who has not been trained on a new piece of equipment.","How would you address a training gap?","I would proactively request training rather than waiting to be caught without the skill. I would say, 'I noticed I have not yet been trained on the new IV pump system. Can we schedule a training session before I need to use it? I do not want to be in a situation where patient care is delayed because of my unfamiliarity.' Taking initiative about training gaps is proactive safety.","Proactive training gap identification and resolution.","beginner"),
  q("sq-bg4-58",pd,"advocacy","A patient's medication is on back-order and there is no approved substitute.","How would you manage a medication supply chain issue?","I would notify the pharmacist about the back-order, explore alternative formulations or routes, contact other hospital pharmacies for supply, discuss therapeutic alternatives with the provider, and ensure the patient is not left without necessary treatment. I would document the supply issue and any treatment modifications. Supply chain issues should never result in treatment gaps.","Supply chain problem-solving for medication access.","intermediate"),
  q("sq-bg4-59",cn,"probation_period","You feel your preceptor does not give you enough independence.","How would you discuss readiness for more independence?","I would approach it as a conversation: 'I really appreciate your guidance and I feel my skills in [specific areas] have grown. I would like to discuss taking on more independent responsibility with [specific tasks] while you remain available for questions. What milestones would you like to see before increasing my independence?' Framing it as a collaborative discussion shows maturity.","Collaborative independence discussion.","beginner"),
  q("sq-bg4-60",ip,"scenario_responses","A patient asks you to help them look up their symptoms online.","How would you handle internet health information requests?","I would acknowledge their desire for information while cautioning about unreliable sources: 'I understand wanting to learn more about your condition. Let me provide you with reliable patient education materials from our hospital or trusted medical websites like MedlinePlus. If you find information online that concerns you, please bring your questions to your care team so we can address them accurately.'","Guiding patients to reliable health information sources.","beginner"),
  q("sq-bg4-61",ws,"handoff_communication","A family member is present during bedside handoff and becomes upset about information shared.","How would you handle family distress during bedside report?","I would pause and address the family member's concern. I would step outside with them if needed to provide privacy. I would explain that bedside handoff is done to improve safety and accuracy. I would verify with the patient beforehand whether they want family present during report and which information can be shared. Patient consent for bedside handoff is essential.","Patient consent and family management during bedside handoff.","intermediate"),
  q("sq-bg4-62",ct,"critical_thinking_drills","A patient's lactate level is 4.5 mmol/L.","What does an elevated lactate indicate?","An elevated lactate (normal <2 mmol/L) indicates tissue hypoperfusion and anaerobic metabolism. Common causes include sepsis, hypovolemia, cardiogenic shock, and severe dehydration. A lactate of 4.5 is concerning for sepsis if accompanied by other SIRS criteria. I would assess for infection sources, obtain blood cultures, anticipate aggressive fluid resuscitation, and monitor lactate clearance as a marker of treatment response.","Lactate as a tissue perfusion biomarker.","intermediate"),
  q("sq-bg4-63",pd,"workplace_bullying","A clique on the unit makes new nurses feel unwelcome.","How would you navigate unit clique dynamics?","I would focus on building professional relationships through competence and reliability rather than trying to join a social group. I would be friendly and professional with everyone. I would seek supportive colleagues and mentors outside the clique. If the clique's behavior affects patient care or creates a hostile work environment, I would address it through proper channels.","Professional relationship building independent of social dynamics.","beginner"),
  q("sq-bg4-64",ip,"clinical_judgment","A patient with a known AAA develops sudden flank pain and hypotension.","What surgical emergency do you suspect?","Sudden flank pain with hypotension in a patient with a known abdominal aortic aneurysm indicates possible rupture—a catastrophic surgical emergency. I would activate the emergency response system, establish two large-bore IV lines, prepare for massive blood transfusion, keep the patient supine, and notify the vascular surgeon STAT. Do not wait for imaging if the clinical picture is clear.","Ruptured AAA recognition with immediate surgical mobilization.","advanced"),
  q("sq-bg4-65",ws,"patient_safety","A patient tells you they feel unsafe because of another patient on the unit.","How would you address a patient's safety concern about another patient?","I would take the concern seriously, assess the specific threat, separate the patients if possible, implement security measures as needed, and notify the charge nurse and security. I would document the patient's concern and the interventions taken. Every patient has the right to feel safe in the hospital environment.","Immediate patient safety assessment and intervention.","beginner"),
  q("sq-bg4-66",ct,"time_management","Your shift starts with receiving a critically ill patient from the OR.","How would you organize your shift when it starts with a complex admission?","I would focus entirely on the post-op admission first: complete assessment, verify all orders, set up monitoring, and stabilize the patient. I would ask a colleague to check on my other patients briefly. Once the new admission is stable, I would quickly round on all other patients, prioritize concerns, and organize the rest of my shift. The first hour may be chaotic, but systematic recovery follows.","Post-op admission prioritization with team support.","intermediate"),
  q("sq-bg4-67",pd,"ethical_dilemmas","You suspect a patient's injury was caused by a healthcare worker.","How would you handle suspected healthcare worker abuse of a patient?","I would document the injury objectively with photographs if policy allows. I would report my suspicion to the charge nurse, risk management, and patient safety officer immediately. I would ensure the suspected worker does not have further access to the patient. I would follow mandatory reporting requirements. Protecting vulnerable patients from all sources of harm—including other healthcare workers—is a fundamental nursing obligation.","Immediate reporting of suspected healthcare worker abuse.","advanced"),
  q("sq-bg4-68",cn,"career_advancement","You want to develop your skills in wound care nursing.","How would you specialize in wound care?","I would seek out wound care cases on my unit, observe wound care nurses, attend wound care courses, pursue WOC (Wound, Ostomy, Continence) certification, and volunteer for wound care committee work. I would learn about advanced wound therapies: negative pressure wound therapy, bioengineered skin substitutes, and hyperbaric oxygen. The wound care specialty requires both clinical expertise and patient education skills.","Wound care specialization pathway.","intermediate"),
  q("sq-bg4-69",ip,"behavioral","Tell me about a time you received mentoring that changed your practice.","How has mentoring influenced your nursing development?","My preceptor noticed that I rushed through patient education because I was anxious about time management. She taught me to slow down and make eye contact during teaching, saying 'Ten minutes of effective education is better than twenty minutes of talking at someone.' I implemented her advice and my patient satisfaction scores for education improved. I now prioritize quality of interaction over quantity of information.","Specific mentoring impact on practice behavior.","beginner"),
  q("sq-bg4-70",ws,"interdisciplinary_communication","A physical therapist tells you the patient is unsafe for discharge but the physician disagrees.","How would you navigate discharge safety disagreements?","I would advocate for a team discussion: 'PT has expressed concerns about discharge safety based on functional assessment. The physician is targeting discharge today. I think we need a brief huddle to align on discharge criteria and ensure we are making the safest decision for the patient.' I would document my advocacy and ensure both perspectives are heard.","Team huddle facilitation for discharge disagreements.","intermediate"),
  q("sq-bg4-71",ip,"clinical_judgment","A patient receiving potassium replacement develops cardiac rhythm changes.","What ECG changes indicate potassium disturbance?","Hypokalemia causes flattened T waves, U waves, and ST depression. Hyperkalemia causes peaked T waves, widened QRS, loss of P waves, and ultimately a sine wave pattern before cardiac arrest. I would stop potassium replacement if hyperkalemia signs appear, verify the latest potassium level, notify the provider, and ensure continuous cardiac monitoring. Potassium directly affects cardiac conduction.","ECG recognition of potassium disturbances.","intermediate"),
  q("sq-bg4-72",ct,"critical_thinking_drills","A patient has an increasing anion gap.","What does a widening anion gap suggest?","An increasing anion gap (normal 8-12) suggests accumulation of unmeasured acids. The mnemonic MUDPILES helps: Methanol, Uremia, DKA, Propylene glycol, Isoniazid/Iron, Lactic acidosis, Ethylene glycol, Salicylates. I would check blood glucose, lactate, BUN/creatinine, and toxicology screen. I would correlate with the patient's clinical picture and history to identify the specific cause.","Anion gap interpretation with MUDPILES differential.","advanced"),
  q("sq-bg4-73",pd,"advocacy","A patient is being discharged without a follow-up appointment scheduled.","How would you ensure post-discharge continuity?","I would not complete discharge without verifying that follow-up appointments are scheduled and the patient knows where and when they occur. I would ensure they have prescriptions, understand their medications, and have transportation to follow-up visits. I would provide the office phone number and instructions for when to call or return to the ED. Post-discharge continuity prevents readmissions.","Comprehensive discharge follow-up verification.","beginner"),
  q("sq-bg4-74",ws,"medication_error","A patient's allergy band is missing when you go to administer medication.","How would you handle a missing allergy band?","I would not administer any medication until allergies are verified. I would check the chart for documented allergies, ask the patient directly about allergies, and replace the allergy band immediately. I would investigate why it was missing—was it removed for a procedure, did it fall off, or was it never applied? I would ensure all patients have accurate, visible allergy identification.","Allergy verification before any medication administration.","beginner"),
  q("sq-bg4-75",ip,"clinical_judgment","A patient with burns develops dark, tea-colored urine.","What does dark urine in a burn patient indicate?","Dark, tea-colored urine in a burn patient suggests myoglobinuria from rhabdomyolysis—muscle protein breakdown from deep burns. Myoglobin can cause acute renal failure if not flushed through the kidneys. I would increase IV fluid rate to maintain urine output >0.5-1 mL/kg/hr, notify the provider, check CK levels, and anticipate possible alkalinization of urine. Renal function monitoring is critical.","Rhabdomyolysis recognition in burn patients.","advanced"),
  q("sq-bg4-76",ws,"difficult_coworkers","A nurse on the unit consistently makes negative comments about nursing as a profession.","How would you handle persistent professional negativity?","I would address it if it affects team morale: 'I notice you seem dissatisfied with nursing. While everyone has challenging days, the constant negativity affects the team. If you are going through a difficult time, there are resources available to help.' If the negativity is chronic and affects new nurse retention, I would discuss the concern with management.","Addressing chronic professional negativity constructively.","intermediate"),
  q("sq-bg4-77",ct,"new_nurse_anxiety","You feel isolated because your orientation cohort peers are on different units.","How would you build connections when separated from your cohort?","I would maintain connections with my cohort through group chats, meetups outside work, and shared study sessions. I would also build relationships on my own unit with experienced nurses, CNAs, and other new graduates. I would join unit committees and participate in social events. Professional isolation is a risk factor for new nurse turnover—proactive connection-building is protective.","Multi-channel relationship building against isolation.","beginner"),
  q("sq-bg4-78",pd,"patient_communication","A patient expresses frustration about being in the hospital during a holiday.","How would you support a patient during a holiday hospitalization?","I would validate their feelings: 'I understand how difficult it is to be here during the holiday. Let me see what we can do to make it special.' I would facilitate video calls with family, help decorate their room if appropriate, arrange for holiday meals if diet allows, and provide extra emotional support. Small gestures can significantly improve their experience during a difficult time.","Humanizing care during holiday hospitalizations.","beginner"),
  q("sq-bg4-79",cn,"performance_evaluation","Your evaluation meets expectations but you are aiming for exceeds expectations.","How would you elevate your performance to exceed expectations?","I would identify the specific criteria for 'exceeds expectations' and create targeted goals. I would go beyond basic job requirements by participating in committees, leading quality improvement projects, mentoring peers, pursuing certifications, and contributing to evidence-based practice. I would document my contributions and bring specific examples to my next evaluation.","Targeted performance elevation with documented evidence.","beginner"),
  q("sq-bg4-80",ip,"scenario_responses","A patient is annoyed that different staff keep asking the same questions.","How would you address patient frustration with repetitive questioning?","I would validate their frustration: 'I understand it is annoying to answer the same questions. We ask because each team member needs to verify information independently for your safety—it is one of our error prevention strategies. I will try to review your chart first to minimize repeated questions while still ensuring accuracy.' I would also check if there are system improvements that could reduce redundancy.","Explaining safety rationale for repetitive verification.","beginner"),
  q("sq-bg4-81",ws,"patient_safety","A patient on anticoagulation needs an IM injection.","How would you handle an IM injection in an anticoagulated patient?","I would verify whether the injection can be given subcutaneously instead, as IM injections in anticoagulated patients carry a higher risk of hematoma formation. If IM is required, I would use the smallest gauge needle appropriate, apply direct pressure for an extended period after injection, monitor for hematoma formation, and document the rationale. I would consult the pharmacist and provider about the route.","Injection route modification for anticoagulated patients.","intermediate"),
  q("sq-bg4-82",ct,"first_shift","A family member is upset because the previous shift did not communicate with them.","How would you recover from another nurse's communication gap?","I would listen to the family's concerns without making excuses for the previous nurse. I would provide the update they need and establish a communication plan: 'Let me catch you up on everything. Going forward, I will update you at [specific times] or whenever there are significant changes. What questions do you have right now?' Proactive recovery builds trust despite previous gaps.","Communication gap recovery with proactive plan.","beginner"),
  q("sq-bg4-83",pd,"ethical_dilemmas","A patient on life support has no advance directive and no family.","How would you navigate end-of-life decisions for a patient without a surrogate?","I would involve social work to search for family or legal representatives, consult the ethics committee, and follow facility policy for unrepresented patients. Many states have laws governing decision-making for patients without surrogates. The ethics committee can provide guidance on treatment decisions that align with the patient's best interests while respecting their dignity.","Ethics committee guidance for unrepresented patients.","advanced"),
  q("sq-bg4-84",cn,"career_advancement","You want to get involved in disaster preparedness nursing.","How would you develop disaster nursing competencies?","I would complete FEMA IS courses (available free online), obtain disaster nursing certification, join the Medical Reserve Corps, participate in hospital disaster drills, and join the Emergency Nurses Association. I would develop skills in triage, resource management, and mass casualty response. I would also understand the psychological impact of disasters on both patients and providers.","Disaster preparedness skill development.","intermediate"),
  q("sq-bg4-85",ip,"clinical_judgment","A patient develops severe abdominal pain after a colonoscopy.","What complication might have occurred?","Severe abdominal pain after colonoscopy could indicate perforation—a tear in the bowel wall. I would assess for peritoneal signs (rigid abdomen, rebound tenderness, guarding), check vital signs for sepsis indicators, keep the patient NPO, and notify the gastroenterologist and surgeon immediately. An upright abdominal X-ray may show free air under the diaphragm. This is a surgical emergency.","Post-colonoscopy perforation recognition.","advanced"),
  q("sq-bg4-86",ws,"handoff_communication","You need to accept handoff for a patient from another department you rarely interact with.","How would you receive handoff from an unfamiliar department?","I would ask for a comprehensive report using SBAR structure and request clarification on anything unfamiliar: 'I am not as familiar with [specialty] protocols. Can you explain what I should be monitoring for with this particular treatment?' I would ask about specific concerns and anticipated complications. I would not pretend to understand something I do not.","Honest knowledge gaps during cross-department handoff.","beginner"),
  q("sq-bg4-87",pd,"professional_boundaries","A former patient sends you a friend request on social media.","How would you handle social media requests from former patients?","I would not accept the request. Professional boundaries extend beyond the active care period. I would follow my facility's social media policy, which typically prohibits social media connections with current or former patients. If the patient contacts me directly, I would explain the professional boundary and wish them well. I would document the contact if needed.","Social media boundary maintenance with former patients.","beginner"),
  q("sq-bg4-88",ct,"documentation_challenges","You realize your assessment documentation does not match what the provider documented.","How would you handle conflicting documentation between nursing and provider notes?","I would review both entries for accuracy. If my documentation is correct, I would not change it. Different perspectives on the same patient are normal and valuable. If there is a significant clinical discrepancy (different heart rhythm, different findings), I would communicate with the provider to reassess the patient together and clarify the record. Both entries should remain with addendums as needed.","Managing documentation discrepancies through collaborative reassessment.","intermediate"),
  q("sq-bg4-89",cn,"job_offer_negotiation","You want to negotiate for a guaranteed day shift position.","How would you negotiate shift preferences realistically?","I would understand that as a new graduate, guaranteed day shift is rare and often based on seniority. I would ask: 'What is the typical timeline for transitioning to a preferred shift? How does shift bidding work? Is there a day-shift opening I could work toward?' Rather than demanding guaranteed days, I would express willingness to work nights initially while understanding the path to preferred scheduling.","Realistic shift negotiation with pathway understanding.","beginner"),
  q("sq-bg4-90",ip,"clinical_judgment","A patient with renal failure develops pericarditis signs—chest pain relieved by leaning forward and a friction rub.","What does pericarditis indicate in a renal patient?","Pericarditis in renal failure indicates uremic pericarditis—toxin accumulation irritating the pericardium. This is an indication for urgent dialysis. I would position the patient leaning forward for comfort, administer pain medication, obtain an ECG (looking for diffuse ST elevation), obtain an echocardiogram to assess for pericardial effusion, and notify the nephrologist for emergent dialysis. Watch for cardiac tamponade.","Uremic pericarditis as a dialysis emergency.","advanced"),
  q("sq-bg4-91",ws,"delegation","You need to delegate care for a patient who speaks only Spanish to a bilingual CNA.","How would you leverage bilingual staff for patient care?","I would ask the bilingual CNA to assist with communication while ensuring clinical assessment and education remain my responsibility. I would use the CNA to help explain comfort measures and basic needs. I would also arrange for a certified medical interpreter for formal education and consent discussions—bilingual staff members are helpful but should not replace certified interpretation for clinical communication.","Appropriate use of bilingual staff with interpreter services.","intermediate"),
  q("sq-bg4-92",ct,"critical_thinking_drills","A patient has a positive fecal occult blood test.","What does a positive FOBT indicate?","A positive fecal occult blood test indicates blood in the stool, which can come from GI bleeding sources including polyps, ulcers, hemorrhoids, inflammatory bowel disease, or colorectal cancer. I would assess for signs of anemia, check hemoglobin, review medications that could cause false positives (NSAIDs, anticoagulants), and notify the provider for further evaluation, likely colonoscopy.","FOBT interpretation with further evaluation anticipation.","beginner"),
  q("sq-bg4-93",pd,"patient_communication","A patient with limited English proficiency needs complex discharge instructions.","How would you ensure comprehensive discharge education with a language barrier?","I would arrange a certified medical interpreter—never rely on family members for medical interpretation. I would use simple language, visual aids, and demonstrated techniques. I would provide written instructions in the patient's language. I would use teach-back through the interpreter to verify understanding. I would arrange for home health follow-up if the complexity warrants ongoing professional support.","Interpreter-mediated comprehensive discharge education.","intermediate"),
  q("sq-bg4-94",cn,"career_advancement","You want to develop expertise in telehealth nursing.","How would you prepare for telehealth nursing?","I would develop strong telephone triage and assessment skills, learn telehealth technology platforms, understand documentation requirements for virtual visits, pursue telehealth nursing certification, and build comfort with remote patient assessment. Telehealth nursing requires excellent communication skills since physical assessment is limited. I would also understand the legal and regulatory framework for telehealth in my state.","Telehealth nursing preparation and skill development.","intermediate"),
  q("sq-bg4-95",ip,"star_examples","Tell me about a time you made a clinical decision under pressure.","Describe decision-making under clinical pressure.","During my last clinical rotation, a patient's blood pressure suddenly dropped to 70/40. While my preceptor was at lunch, I immediately assessed the patient, laid them flat, increased their IV fluid rate, called for the charge nurse, and prepared to notify the physician. My preceptor returned to find the patient stabilized and commended my systematic response. The experience proved I could think clearly under pressure.","Systematic emergency response demonstrating clinical competence.","intermediate"),
  q("sq-bg4-96",ws,"patient_safety","A patient on neutropenic precautions wants fresh flowers from a visitor.","How would you address flowers for a neutropenic patient?","I would explain that fresh flowers and plants are not allowed for neutropenic patients because they can harbor bacteria and fungi that pose infection risk to immunocompromised patients. I would suggest alternatives: silk flowers, cards, photos, or electronic photo frames. I would appreciate the visitor's thoughtfulness while explaining the clinical rationale for the restriction.","Infection prevention education for neutropenic patients.","beginner"),
  q("sq-bg4-97",ip,"clinical_judgment","A patient on TPN develops hyperglycemia despite not being diabetic.","Why does TPN cause hyperglycemia and how would you manage it?","TPN contains high concentrations of dextrose that can cause hyperglycemia, especially in stressed, septic, or steroid-treated patients. I would monitor blood glucose per protocol (typically every 6 hours initially), administer sliding scale insulin as ordered, notify the provider for persistent hyperglycemia, and anticipate insulin being added to the TPN formulation. Tight glucose control reduces infection risk.","TPN-related hyperglycemia management.","intermediate"),
  q("sq-bg4-98",pd,"advocacy","A patient's cultural practice involves burning herbs, which conflicts with hospital fire safety.","How would you accommodate cultural practices within safety constraints?","I would explore safe alternatives that honor the cultural practice: unlit herbs at the bedside, essential oil substitutes, or arranging a supervised outdoor area for the practice. I would involve the chaplain or cultural liaison. I would explain the fire safety concern respectfully while actively seeking accommodations. Cultural practices should be honored as much as safely possible.","Creative cultural accommodation within safety parameters.","intermediate"),
  q("sq-bg4-99",ct,"time_management","You realize you have been spending too much time on charting and not enough on patient care.","How would you rebalance documentation and direct care time?","I would analyze where I am spending excessive documentation time—narrative notes, flowsheets, or care plans. I would learn system shortcuts and templates. I would chart at the point of care rather than batching at the nurses' station. I would set a time limit for documentation and prioritize clinical documentation over administrative charting. Direct patient care should always be the priority.","Documentation efficiency for more bedside time.","beginner"),
  q("sq-bg4-100",cn,"career_advancement","You are interested in occupational health nursing.","How would you transition to occupational health nursing?","I would develop knowledge in workplace safety, OSHA regulations, workers' compensation, and health promotion. I would pursue Certified Occupational Health Nurse (COHN) certification. I would learn about ergonomic assessment, workplace injury prevention, and drug testing protocols. Occupational health nursing combines clinical skills with public health and regulatory knowledge. Prior experience in emergency or outpatient nursing is beneficial.","Occupational health nursing career pathway.","intermediate"),
];
